// Worked focus: httpsts-resource-representation-storage — Separate resource identity, server state, selected representation, transfer content, TypeScript model, and PostgreSQL rows.
// Evidence: httpsts-worked-http-server-ts-http-semantics-resources-3
// Competency: httpsts-worked-http-server-ts-http-semantics-resources-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_http_semantics_resources_3(method: string, exists: boolean, validatorMatches: boolean): { status: number; mutates: boolean } {
  const normalized = method.toUpperCase();
  if (normalized === "GET") return { status: exists ? 200 : 404, mutates: false };
  if (normalized === "PUT" && !validatorMatches) return { status: 412, mutates: false };
  if (normalized === "PUT") return { status: exists ? 200 : 201, mutates: true };
  return { status: 405, mutates: false };
}

